import { renderToStaticMarkup } from 'react-dom/server'
function TagList({ tags }) {
  const seen = new Set();
  const unique = tags.filter((t) => {
    if (seen.has(t)) return false;
    seen.add(t);
    return true;
  });
  return <p>{unique.join("、")}</p>;
}
console.log(renderToStaticMarkup(<TagList tags={["紅", "綠", "紅"]} />));

