// 版本一：在渲染時發送請求
function Profile({ id }) {
  fetch(`/api/user/${id}`);   // 每算一次畫面就打一次
  return <p>使用者 {id}</p>;
}

// 版本二：把請求放進 Effect
function Profile2({ id }) {
  useEffect(() => {
    fetch(`/api/user/${id}`);
  }, [id]);
  return <p>使用者 {id}</p>;
}
